package main

import (
	"fmt"
)

func InputFormat(str string) [][]rune {
	return [][]rune{}
}

func InString(rune []rune) string {
	str := string(rune)
	return str
}

func main() {

	f := make([][]rune, 30)

	for i := range f {
		f[i] = make([]rune, 30)
	}

	var input string
	fmt.Scan(input)
	txt := InputFormat(input)

	for j := range len(txt) {
		for i := range len(txt[j]) {
			fmt.Println(InString(txt[i]))
		}
	}
}
